/**
 * SDK instance providing the public API for merchants.
 * Created via createNylonPay factory function.
 *
 * @see Spec 2 section 2 - "this returns an instance of the sdk that they can call methods on such as collectPayment with needed details and fields"
 */

import { Err, Ok, type Result } from 'slang-ts';
import { createPaymentInstance } from './payment';
import { createTransport } from './transport';
import type {
  CollectionResponse,
  CreateCollectionRequest,
  GetStatusRequest,
  NylonPayConfig,
  PaymentInstance,
  StatusResponse,
  Transaction,
} from './types';

const UUID_V4_REGEX =
  /^[0-9a-f]{8}-[0-9a-f]{4}-4[0-9a-f]{3}-[89ab][0-9a-f]{3}-[0-9a-f]{12}$/i;

/**
 * SDK instance interface returned from createNylonPay().
 * Provides methods for interacting with Nylon Pay.
 */
export interface NylonPaySdk {
  /**
   * Initiate a collection payment.
   * Returns immediately with processing status; use returned instance for events.
   *
   * @param request - Collection request details
   * @returns Payment instance for event subscription and waiting
   *
   * @example
   * ```ts
   * const payment = await nylonpay.collectPayment({
   *   amount: 10000,
   *   currency: 'UGX',
   *   reference: 'ORDER-123',
   *   method: 'mobile-money',
   *   description: 'Mobile money payment',
   *   customer: {
   *     phone: '+256700000000',
   *   },
   * });
   *
   * payment.on("success", (data) => {
   *   console.log("Payment succeeded!", data);
   * });
   * ```
   */
  collectPayment(request: CreateCollectionRequest): Promise<PaymentInstance>;

  /**
   * Get the current status of a transaction.
   * Polls the provider for the latest status.
   *
   * @param request - Status request with reference ID
   * @returns Transaction details and provider status
   */
  getStatus(request: GetStatusRequest): Promise<Result<StatusResponse, string>>;

  /**
   * Create an invoice via SDK auth.
   * @see Spec 2 section 2 - "The merchant through our sdk, may first issue an invoice"
   *
   * @param request - Invoice details
   * @returns Created invoice with payment link
   */
  createInvoice(
    request: CreateInvoiceRequest,
  ): Promise<Result<InvoiceResponse, string>>;
}

/**
 * Request for creating an invoice via SDK.
 */
export interface CreateInvoiceRequest {
  amount: number;
  currency?: string;
  customerEmail?: string;
  customerPhone?: string;
  description?: string;
  dueDate?: string;
  metadata?: Record<string, unknown>;
}

/**
 * Response from invoice creation.
 */
export interface InvoiceResponse {
  invoiceNumber: string;
  paymentLink: string;
  amount: string;
  currency: string;
  status: string;
  createdAt: string;
}

/**
 * Create an SDK instance with the given configuration.
 * This is the main entry point merchants use.
 *
 * @param config - SDK configuration
 * @returns SDK instance with collectPayment, getStatus, createInvoice
 *
 * @internal
 */
export function createSdkInstance(
  config: Required<NylonPayConfig>,
): NylonPaySdk {
  const transport = createTransport(config);

  /**
   * Initiate a collection payment.
   */
  async function collectPayment(
    request: CreateCollectionRequest,
  ): Promise<PaymentInstance> {
    if (!UUID_V4_REGEX.test(request.reference)) {
      return createPaymentInstance(
        {
          transactionId: '',
          reference: request.reference,
          status: 'failed',
          createdAt: new Date().toISOString(),
        },
        {
          fetchStatus: async () => Err('Reference must be a valid UUID v4'),
          pollIntervalMs: 0,
          maxPollAttempts: config.maxPollAttempts,
          maxPollDuration: config.maxPollDuration,
        },
      );
    }

    const body = {
      amount: request.amount,
      currency: request.currency ?? 'UGX',
      customer: {
        phoneNumber: request.customer.phone,
        email: request.customer.email,
      },
      reference: request.reference,
      invoiceNumber: request.invoiceNumber,
      notifyMerchant: request.notifyMerchant ?? true,
      metadata: {
        ...request.metadata,
        method: request.method,
        description: request.description,
      },
    };

    const result = await transport.send<CollectionResponse>({
      action: 'collections/create-collection',
      body,
      requiresAuth: true,
    });

    if (!result.isOk) {
      // Return a payment instance that immediately emits error
      const errorMessage = result.error;
      const payment = createPaymentInstance(
        {
          transactionId: '',
          reference: request.reference,
          status: 'failed',
          createdAt: new Date().toISOString(),
        },
        {
          fetchStatus: async () => Err(errorMessage),
          pollIntervalMs: 0,
          maxPollAttempts: config.maxPollAttempts,
          maxPollDuration: config.maxPollDuration,
        },
      );
      return payment;
    }

    // Create payment instance that polls for status
    return createPaymentInstance(result.value, {
      fetchStatus: async (getStatusReq) => {
        const statusResult = await transport.send<StatusResponse>({
          action: 'collections/get-collection-status',
          body: getStatusReq,
          requiresAuth: true,
        });
        if (statusResult.isOk) {
          return Ok(statusResult.value);
        }
        return Err(statusResult.error);
      },
      maxPollAttempts: config.maxPollAttempts,
      maxPollDuration: config.maxPollDuration,
    });
  }

  /**
   * Get the current status of a transaction.
   */
  async function getStatus(
    request: GetStatusRequest,
  ): Promise<Result<StatusResponse, string>> {
    const result = await transport.send<StatusResponse>({
      action: 'collections/get-collection-status',
      body: request,
      requiresAuth: true,
    });

    if (result.isOk) {
      return Ok(result.value);
    }

    return Err(result.error);
  }

  /**
   * Create an invoice via SDK auth.
   */
  async function createInvoice(
    request: CreateInvoiceRequest,
  ): Promise<Result<InvoiceResponse, string>> {
    const body = {
      amount: request.amount,
      currency: request.currency ?? 'UGX',
      customerEmail: request.customerEmail,
      customerPhone: request.customerPhone,
      description: request.description,
      dueDate: request.dueDate,
      metadata: request.metadata,
    };

    const result = await transport.send<InvoiceResponse>({
      action: 'invoices/create-invoice',
      body,
      requiresAuth: true,
    });

    if (result.isOk) {
      return Ok(result.value);
    }

    return Err(result.error);
  }

  return {
    collectPayment,
    getStatus,
    createInvoice,
  };
}
