/**
 * HTTP transport layer for SDK communication with backend.
 * Handles auth headers, retries, timeouts, and error mapping.
 *
 * @see Spec 2 section 1 - "sends a request to our backend with all these other values such as the nonce in the headers"
 */

import { Err, Ok, type Result } from 'slang-ts';
import { generateFingerprint } from './fingerprint';
import { generateNonce } from './nonce';
import { createSignature, createTimestamp } from './signature';
import { verifyResponseSignature } from './verify-response';
import type {
  NylonPayConfig,
  SdkAuthHeaders,
  SdkError,
  TransportRequest,
} from './types';

/**
 * HTTP status codes that indicate retryable failures.
 * @internal
 */
const RETRYABLE_STATUS_CODES = new Set([408, 429, 500, 502, 503, 504]);

/**
 * Cached fingerprint for this server instance.
 * Generated once and reused for all requests.
 * @internal
 */
const CACHED_FINGERPRINT = generateFingerprint();

/**
 * Serialize an SdkError to a JSON string for transport.
 * @internal
 */
function serializeError(error: SdkError): string {
  return JSON.stringify(error);
}

/**
 * Deserialize an SdkError from a JSON string.
 * @internal
 */
function deserializeError(error: string): SdkError {
  try {
    return JSON.parse(error) as SdkError;
  } catch {
    return { code: 'UNKNOWN', message: error };
  }
}

/**
 * Calculate exponential backoff delay with jitter.
 * @internal
 */
function calculateBackoff(attempt: number): number {
  const base = 2 ** attempt * 1000; // 1s, 2s, 4s
  const jitter = Math.random() * 500;
  return base + jitter;
}

/**
 * Promise-based delay.
 * @internal
 */
function delay(ms: number): Promise<void> {
  return new Promise((resolve) => setTimeout(resolve, ms));
}

function stripResponseSignature<T>(payload: T): {
  data: T;
  responseSignature: string | null;
} {
  if (
    !payload ||
    typeof payload !== 'object' ||
    !('_responseSignature' in payload)
  ) {
    return {
      data: payload,
      responseSignature: null,
    };
  }

  const { _responseSignature, ...rest } = payload as Record<string, unknown>;

  return {
    data: rest as T,
    responseSignature:
      typeof _responseSignature === 'string' ? _responseSignature : null,
  };
}

/**
 * Create the transport layer for SDK requests.
 *
 * @param config - SDK configuration
 * @returns Transport functions
 *
 * @internal
 */
export function createTransport(config: Required<NylonPayConfig>) {
  const {
    apiKey,
    apiSecret,
    baseUrl,
    timeoutMs,
    maxRetries,
    fetch: fetchImpl,
  } = config;

  /**
   * Build auth headers for an SDK request.
   * Matches SDK_HEADER_KEYS in backend/src/services/sdk/constants.ts
   *
   * Security: The server fingerprint is NOT sent in headers to avoid
   * exposing server metadata (OS, runtime, hostname) in plain text.
   * Instead, it is included in the signed request body (_fingerprint field).
   * The HMAC signature ensures the fingerprint cannot be modified.
   */
  function buildAuthHeaders(payload: unknown): SdkAuthHeaders {
    const nonce = generateNonce();
    const timestamp = createTimestamp();
    const signature = createSignature({
      fingerprint: CACHED_FINGERPRINT,
      nonce,
      timestamp,
      payload,
      secret: apiSecret,
    });

    return {
      'x-nylon-key': apiKey,
      'x-nylon-nonce': nonce,
      'x-nylon-signature': signature,
      'x-nylon-timestamp': timestamp,
    };
  }

  /**
   * Build the request body with fingerprint embedded.
   * The fingerprint is included in the body (not headers) for security.
   */
  function buildRequestBody(payload: unknown): unknown {
    return {
      ...(payload as Record<string, unknown>),
      _fingerprint: CACHED_FINGERPRINT,
    };
  }

  /**
   * Create an AbortController with timeout.
   */
  function withTimeout(signal?: AbortSignal): {
    controller: AbortController;
    cleanup: () => void;
  } {
    const controller = new AbortController();
    const timeoutId = setTimeout(() => controller.abort(), timeoutMs);

    // If parent signal is provided, respect it
    if (signal) {
      if (signal.aborted) {
        controller.abort();
      } else {
        signal.addEventListener('abort', () => controller.abort(), {
          once: true,
        });
      }
    }

    return {
      controller,
      cleanup: () => clearTimeout(timeoutId),
    };
  }

  /**
   * Execute a single HTTP request with retry logic.
   * @see Spec 2 section 2 - "sdk handles polling and retries"
   */
  async function executeWithRetry<T>(
    request: TransportRequest,
    attempt = 0,
  ): Promise<Result<T, string>> {
    const { controller, cleanup } = withTimeout(request.signal);

    try {
      const headers: Record<string, string> = {
        'content-type': 'application/json',
      };

      // Build body with fingerprint for authenticated requests
      let body = request.body;
      if (request.requiresAuth) {
        body = buildRequestBody(request.body);
        Object.assign(headers, buildAuthHeaders(body));
      }

      const url = `${baseUrl}/${request.action}`;
      const response = await fetchImpl(url, {
        method: 'POST',
        headers,
        body: JSON.stringify(body),
        signal: controller.signal,
      });

      cleanup();

      if (!response.ok) {
        const statusCode = response.status;
        const retryable = RETRYABLE_STATUS_CODES.has(statusCode);
        let errorMessage = `HTTP ${statusCode}`;

        try {
          const errorBody = await response.json();
          if (
            errorBody &&
            typeof errorBody === 'object' &&
            'message' in errorBody
          ) {
            errorMessage = String(errorBody.message);
          }
        } catch {
          // Response body not JSON, use status text
          errorMessage = response.statusText || errorMessage;
        }

        // Retry on retryable status codes
        if (retryable && attempt < maxRetries) {
          await delay(calculateBackoff(attempt));
          return executeWithRetry<T>(request, attempt + 1);
        }

        const sdkError: SdkError = {
          code: `HTTP_${statusCode}`,
          message: errorMessage,
          statusCode,
          retryable,
        };
        return Err(serializeError(sdkError));
      }

      const payload = (await response.json()) as T;
      const { data, responseSignature } = stripResponseSignature(payload);

      if (!request.requiresAuth || !responseSignature) {
        return Ok(data);
      }

      const isValidResponse = verifyResponseSignature(
        data,
        responseSignature,
        apiSecret,
      );
      if (!isValidResponse) {
        return Err(
          serializeError({
            code: 'RESPONSE_TAMPERED',
            message: 'Authenticated response signature verification failed',
            retryable: false,
          }),
        );
      }

      return Ok(data);
    } catch (error) {
      cleanup();

      const isAbort =
        error instanceof DOMException && error.name === 'AbortError';
      const sdkError: SdkError = {
        code: isAbort ? 'TIMEOUT' : 'NETWORK_ERROR',
        message: isAbort
          ? `Request timed out after ${timeoutMs}ms`
          : String(error),
        retryable: true,
      };

      // Retry on timeout/network errors
      if (attempt < maxRetries) {
        await delay(calculateBackoff(attempt));
        return executeWithRetry<T>(request, attempt + 1);
      }

      return Err(serializeError(sdkError));
    }
  }

  /**
   * Send a request to the backend.
   * Returns Result<T, string> where the error string is a JSON-serialized SdkError.
   */
  async function send<T>(
    request: TransportRequest,
  ): Promise<Result<T, string>> {
    return executeWithRetry<T>(request);
  }

  return { send, parseError };
}

/**
 * Parse an error string into an SdkError object.
 * Useful for handling errors from the SDK.
 *
 * @example
 * ```ts
 * const result = await sdk.collectPayment(request);
 * if (!result.isOk) {
 *   const sdkError = parseError(result.error);
 *   console.log(sdkError.code, sdkError.message);
 * }
 * ```
 */
export function parseError(error: string): SdkError {
  return deserializeError(error);
}
